// Logging para debug
console.log(`Total inicial - Lista1: ${lista1.length}, Lista2: ${lista2.length}, JSON: ${json.length}`);

// Mapa para acelerar a busca (indexação)
const pessoasPorCodigo = {};
lista1.forEach(pessoa => {
    if (pessoa.codigo) {
        if (!pessoasPorCodigo[pessoa.codigo]) {
            pessoasPorCodigo[pessoa.codigo] = [];
        }
        pessoasPorCodigo[pessoa.codigo].push(pessoa);
    }
});

const detalhesPorCRM = {};
lista2.forEach(detalhe => {
    if (detalhe.CRM) {
        detalhesPorCRM[detalhe.CRM] = detalhe;
    }
});

// Contadores para diagnóstico
let contadorSemCodigo = 0;
let contadorSemPessoa = 0;
let contadorSemDetalhe = 0;
let contadorProcessados = 0;

// Processa os itens
const combinedData = [];
json.forEach(item => {
    // Verifica se o item tem código
    if (!item.codigo) {
        contadorSemCodigo++;
        return; // Pula este item
    }

    // Busca pessoas correspondentes pelo código (pode haver mais de uma)
    const pessoasEncontradas = pessoasPorCodigo[item.codigo] || [];
    
    if (pessoasEncontradas.length === 0) {
        contadorSemPessoa++;
        // Opção: incluir mesmo sem pessoa (remova o return se quiser isso)
        return;
    }

    // Para cada pessoa correspondente, cria um item no resultado
    pessoasEncontradas.forEach(pessoa => {
        // Busca detalhes pelo CRM
        const detalhes = pessoa.CRM ? detalhesPorCRM[pessoa.CRM] : null;
        
        if (!detalhes) {
            contadorSemDetalhe++;
            // Opção: incluir mesmo sem detalhes (não retorna)
        }

        // Adiciona ao resultado final
        combinedData.push({
            "tipo": "395",
            "pessoa": {
                "id": pessoa ? pessoa.idPessoa : null
            },
            "curso": item.id,
            "camposPersonalizados": {
                "campopersonalizado_12_compl_proc": detalhes ? detalhes.especialidade2 || "" : "",
                "campopersonalizado_13_compl_proc": detalhes ? detalhes.especialidade3 || "" : "",
                "campopersonalizado_175_compl_proc": detalhes ? detalhes.areaAtuacao || "" : "",
                "campopersonalizado_176_compl_proc": detalhes ? detalhes.areaAtuacao2 || "" : "",
                "campopersonalizado_177_compl_proc": detalhes ? detalhes.areaAtuacao3 || "" : "",
            },
            "origem": "9",
            "token": "d2cc15f39418956cd23eca96b49681ec"
        });
        
        contadorProcessados++;
    });
});

// Filtragem final (mais permissiva)
const dadosFiltrados = combinedData.filter(item => {
    // Verifica se o ID da pessoa é não-nulo
    const temPessoa = item.pessoa && item.pessoa.id !== null;
    // Verifica se o curso existe
    const temCurso = item.curso !== undefined && item.curso !== null;
    
    return temPessoa && temCurso;
});

// Exibe o JSON resultante
console.log(JSON.stringify(dadosFiltrados, null, 2));

// Exibe estatísticas
console.log(`\nEstatísticas de processamento:`);
console.log(`- Total de itens JSON: ${json.length}`);
console.log(`- Itens sem código: ${contadorSemCodigo}`);
console.log(`- Itens sem pessoa correspondente: ${contadorSemPessoa}`);
console.log(`- Itens sem detalhes correspondentes: ${contadorSemDetalhe}`);
console.log(`- Itens processados: ${contadorProcessados}`);
console.log(`- Total após filtragem final: ${dadosFiltrados.length}`);
